import React, { useState } from 'react';

const App = () => {
  const [postStatus, setPostStatus] = useState('Draft');
  const handleToggle = () => {
    setPostStatus(postStatus === 'Draft' ? 'Published' : 'Draft');
  };

  return (
    <div className="max-w-md mx-auto p-4 bg-white rounded-md shadow-md">
      <h2 className="text-lg font-bold mb-2">Post Title</h2>
      <button
        className={`bg-${postStatus === 'Draft' ? 'blue-400' : 'green-400'} hover:bg-${postStatus === 'Draft' ? 'blue-500' : 'green-500'} text-white py-2 px-4 rounded-md `}
        onClick={handleToggle}
      >
        {postStatus === 'Draft' ? 'Publish' : 'Draft'}
      </button>
    </div>
  );
};

export default App;
